1	//! The authenticated principal — what the auth guard puts into request state
2	//! and what every authorization helper receives.
3	//!
4	//! A `Principal` is always the result of a verified bearer token on an
5	//! active session. Unauthenticated callers never get a `Principal`; they
6	//! get `AppError::Unauthorized` from the guard.
7	
8	use serde::{Deserialize, Serialize};
9	use uuid::Uuid;
10	
11	/// The five fixed roles in the RBAC model. Stored in the database under
12	/// `roles.name` as lowercase snake_case.
13	#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
14	#[serde(rename_all = "snake_case")]
15	pub enum Role {
16	    Admin,
17	    Librarian,
18	    DepartmentHead,
19	    Instructor,
20	    Viewer,
21	}
22	
23	impl Role {
24	    pub fn as_db_name(self) -> &'static str {
25	        match self {
26	            Role::Admin => "admin",
27	            Role::Librarian => "librarian",
28	            Role::DepartmentHead => "department_head",
29	            Role::Instructor => "instructor",
30	            Role::Viewer => "viewer",
31	        }
32	    }
33	
34	    pub fn from_db_name(name: &str) -> Option<Self> {
35	        match name {
36	            "admin" => Some(Role::Admin),
37	            "librarian" => Some(Role::Librarian),
38	            "department_head" => Some(Role::DepartmentHead),
39	            "instructor" => Some(Role::Instructor),
40	            "viewer" => Some(Role::Viewer),
41	            _ => None,
42	        }
43	    }
44	
45	    /// Monotonic privilege level, used for hierarchy-style checks
46	    /// (e.g. "any role at least as privileged as Librarian").
47	    pub fn level(self) -> u8 {
48	        match self {
49	            Role::Admin => 100,
50	            Role::Librarian => 80,
51	            Role::DepartmentHead => 60,
52	            Role::Instructor => 40,
53	            Role::Viewer => 20,
54	        }
55	    }
56	}
57	
58	/// Everything authorization code needs to know about the caller.
59	#[derive(Debug, Clone, Serialize)]
60	pub struct Principal {
61	    pub user_id: Uuid,
62	    pub session_id: Uuid,
63	    pub email: String,
64	    pub display_name: String,
65	    pub roles: Vec<Role>,
66	    pub department_id: Option<Uuid>,
67	}
68	
69	impl Principal {
70	    pub fn has_role(&self, role: Role) -> bool {
71	        self.roles.iter().any(|r| *r == role)
72	    }
73	
74	    pub fn is_admin(&self) -> bool {
75	        self.has_role(Role::Admin)
76	    }
77	
78	    pub fn max_role_level(&self) -> u8 {
79	        self.roles.iter().map(|r| r.level()).max().unwrap_or(0)
80	    }
81	
82	    /// True if any of the caller's roles meets the minimum level.
83	    pub fn at_least(&self, min: Role) -> bool {
84	        self.max_role_level() >= min.level()
85	    }
86	}
87	
88	#[cfg(test)]
89	mod tests {
90	    use super::*;
91	
92	    #[test]
93	    fn role_db_name_round_trips() {
94	        for r in [
95	            Role::Admin,
96	            Role::Librarian,
97	            Role::DepartmentHead,
98	            Role::Instructor,
99	            Role::Viewer,
100	        ] {
101	            assert_eq!(Role::from_db_name(r.as_db_name()), Some(r));
102	        }
103	        assert_eq!(Role::from_db_name("nope"), None);
104	    }
105	
106	    #[test]
107	    fn level_ordering_matches_privilege() {
108	        assert!(Role::Admin.level() > Role::Librarian.level());
109	        assert!(Role::Librarian.level() > Role::DepartmentHead.level());
110	        assert!(Role::DepartmentHead.level() > Role::Instructor.level());
111	        assert!(Role::Instructor.level() > Role::Viewer.level());
112	    }
113	
114	    #[test]
115	    fn principal_at_least_respects_hierarchy() {
116	        let p = Principal {
117	            user_id: Uuid::nil(),
118	            session_id: Uuid::nil(),
119	            email: "x@y".into(),
120	            display_name: "x".into(),
121	            roles: vec![Role::Librarian],
122	            department_id: None,
123	        };
124	        assert!(p.at_least(Role::Viewer));
125	        assert!(p.at_least(Role::Instructor));
126	        assert!(p.at_least(Role::Librarian));
127	        assert!(!p.at_least(Role::Admin));
128	    }
129	}
