1	//! Common types re-exported for use across the Scholarly frontend.
2	//!
3	//! Centralises domain types so that page components, hooks, and state
4	//! modules can import from one place.
5	
6	use serde::{Deserialize, Serialize};
7	
8	/// User roles in the Scholarly system.
9	///
10	/// Ordered from most privileged to least privileged.
11	#[derive(Clone, Debug, PartialEq, Eq, Serialize, Deserialize)]
12	pub enum Role {
13	    Admin,
14	    Librarian,
15	    DepartmentHead,
16	    Instructor,
17	    Viewer,
18	}
19	
20	impl Role {
21	    /// Returns a numeric privilege level for comparison.
22	    ///
23	    /// Higher values indicate greater privilege.
24	    pub fn level(&self) -> u8 {
25	        match self {
26	            Role::Admin => 100,
27	            Role::Librarian => 80,
28	            Role::DepartmentHead => 60,
29	            Role::Instructor => 40,
30	            Role::Viewer => 20,
31	        }
32	    }
33	
34	    /// Parses a snake-case role string (as emitted by the backend) into a
35	    /// [`Role`]. Unknown values return `None`.
36	    pub fn from_str(value: &str) -> Option<Role> {
37	        match value {
38	            "admin" => Some(Role::Admin),
39	            "librarian" => Some(Role::Librarian),
40	            "department_head" => Some(Role::DepartmentHead),
41	            "instructor" => Some(Role::Instructor),
42	            "viewer" => Some(Role::Viewer),
43	            _ => None,
44	        }
45	    }
46	
47	    /// Returns the snake-case wire representation for this role.
48	    pub fn as_snake(&self) -> &'static str {
49	        match self {
50	            Role::Admin => "admin",
51	            Role::Librarian => "librarian",
52	            Role::DepartmentHead => "department_head",
53	            Role::Instructor => "instructor",
54	            Role::Viewer => "viewer",
55	        }
56	    }
57	}
58	
59	impl Default for Role {
60	    fn default() -> Self {
61	        Role::Viewer
62	    }
63	}
64	
65	impl std::fmt::Display for Role {
66	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
67	        let label = match self {
68	            Role::Admin => "Admin",
69	            Role::Librarian => "Librarian",
70	            Role::DepartmentHead => "Department Head",
71	            Role::Instructor => "Instructor",
72	            Role::Viewer => "Viewer",
73	        };
74	        write!(f, "{}", label)
75	    }
76	}
77	
78	/// Represents an authenticated user in the system.
79	#[derive(Clone, Debug, Default, Serialize, Deserialize, PartialEq)]
80	pub struct User {
81	    /// Unique user identifier.
82	    pub id: String,
83	    /// Email address.
84	    pub email: String,
85	    /// Human-readable display name.
86	    pub display_name: String,
87	    /// Roles assigned to the user. The backend may assign multiple roles.
88	    pub roles: Vec<Role>,
89	    /// Department scoping, if any.
90	    pub department_id: Option<String>,
91	}
