1	//! RoleBadge component — displays a coloured badge for a user role.
2	
3	use dioxus::prelude::*;
4	use crate::types::Role;
5	
6	/// Renders a small badge indicating the user's role.
7	///
8	/// TODO: Map each role to a distinct colour.
9	#[component]
10	pub fn RoleBadge(role: Role) -> Element {
11	    let label = match role {
12	        Role::Admin => "Admin",
13	        Role::Librarian => "Librarian",
14	        Role::Instructor => "Instructor",
15	        Role::DepartmentHead => "Dept. Head",
16	        Role::Viewer => "Viewer",
17	    };
18	
19	    rsx! {
20	        span { class: "role-badge", "{label}" }
21	    }
22	}
