1	//! Main application layout — top bar + sidebar navigation + content
2	//! area.
3	//!
4	//! The layout is role-aware: navigation items declare the minimum role
5	//! required to see them, and the sidebar filters items accordingly.
6	//! Unauthenticated users are redirected to `/login` via a side effect.
7	
8	use dioxus::prelude::*;
9	use dioxus_router::prelude::*;
10	
11	use crate::api::auth;
12	use crate::router::AppRoute;
13	use crate::state::AuthState;
14	use crate::types::Role;
15	
16	// ---------------------------------------------------------------------------
17	// Navigation definition
18	// ---------------------------------------------------------------------------
19	
20	/// A single item in the sidebar navigation.
21	#[derive(Clone, Debug)]
22	pub struct NavItem {
23	    /// Display label shown in the sidebar.
24	    pub label: &'static str,
25	    /// Route this item navigates to.
26	    pub route: AppRoute,
27	    /// Minimum role required to see this item. `None` means visible to all
28	    /// authenticated users.
29	    pub required_role: Option<Role>,
30	    /// Optional section heading rendered above this item when it is the
31	    /// first entry in a logical group.
32	    pub section: Option<&'static str>,
33	}
34	
35	/// Returns the full ordered list of navigation items for the sidebar.
36	///
37	/// Items are grouped into logical sections via the `section` field.
38	pub fn navigation_items() -> Vec<NavItem> {
39	    vec![
40	        NavItem {
41	            label: "Dashboard",
42	            route: AppRoute::Dashboard {},
43	            required_role: None,
44	            section: None,
45	        },
46	        // -- Library --
47	        NavItem {
48	            label: "Journals",
49	            route: AppRoute::JournalList {},
50	            required_role: None,
51	            section: Some("Library"),
52	        },
53	        NavItem {
54	            label: "Resources",
55	            route: AppRoute::ResourceList {},
56	            required_role: None,
57	            section: None,
58	        },
59	        // -- Courses --
60	        NavItem {
61	            label: "Courses",
62	            route: AppRoute::CourseList {},
63	            required_role: None,
64	            section: Some("Courses"),
65	        },
66	        // -- Operations --
67	        NavItem {
68	            label: "Import / Export",
69	            route: AppRoute::Imports {},
70	            required_role: Some(Role::DepartmentHead),
71	            section: Some("Operations"),
72	        },
73	        NavItem {
74	            label: "Check-In",
75	            route: AppRoute::CheckIn {},
76	            required_role: Some(Role::Librarian),
77	            section: None,
78	        },
79	        // -- Analytics --
80	        NavItem {
81	            label: "Reports",
82	            route: AppRoute::Reports {},
83	            required_role: Some(Role::DepartmentHead),
84	            section: Some("Analytics"),
85	        },
86	        NavItem {
87	            label: "Metrics",
88	            route: AppRoute::Metrics {},
89	            required_role: Some(Role::DepartmentHead),
90	            section: None,
91	        },
92	        NavItem {
93	            label: "Audit Logs",
94	            route: AppRoute::AuditLogs {},
95	            required_role: Some(Role::Admin),
96	            section: None,
97	        },
98	        // -- Admin --
99	        NavItem {
100	            label: "Settings",
101	            route: AppRoute::AdminSettings {},
102	            required_role: Some(Role::Admin),
103	            section: Some("Admin"),
104	        },
105	        NavItem {
106	            label: "Retention",
107	            route: AppRoute::RetentionSettings {},
108	            required_role: Some(Role::Admin),
109	            section: None,
110	        },
111	    ]
112	}
113	
114	// ---------------------------------------------------------------------------
115	// Helper — role visibility check
116	// ---------------------------------------------------------------------------
117	
118	/// Returns `true` if `user_role` satisfies the `required` role constraint.
119	fn role_has_access(user_role: &Role, required: &Option<Role>) -> bool {
120	    match required {
121	        None => true,
122	        Some(req) => user_role.level() >= req.level(),
123	    }
124	}
125	
126	// ---------------------------------------------------------------------------
127	// Layout component
128	// ---------------------------------------------------------------------------
129	
130	/// Main layout component rendered around all authenticated routes.
131	///
132	/// Provides the top bar, sidebar navigation, and a content area that is
133	/// filled by the active child route via `Outlet`.
134	#[component]
135	pub fn MainLayout() -> Element {
136	    let mut auth_state = use_context::<Signal<AuthState>>();
137	    let navigator = use_navigator();
138	
139	    // Redirect unauthenticated visitors to /login. Running the push
140	    // inside `use_effect` avoids mutating the router during rendering.
141	    let authed = auth_state.read().is_authenticated();
142	    use_effect(move || {
143	        if !auth_state.read().is_authenticated() {
144	            navigator.push(AppRoute::Login {});
145	        }
146	    });
147	
148	    if !authed {
149	        // Render an empty placeholder while the effect pushes the
150	        // user to the login page on the next tick.
151	        return rsx! { div {} };
152	    }
153	
154	    let snapshot = auth_state.read().clone();
155	    let current_role = snapshot.primary_role().unwrap_or(Role::Viewer);
156	    let display_name = snapshot
157	        .user
158	        .as_ref()
159	        .map(|u| u.display_name.clone())
160	        .unwrap_or_else(|| "Unknown user".to_string());
161	
162	    let nav_items = navigation_items();
163	
164	    let on_logout = move |_| {
165	        let token = auth_state
166	            .read()
167	            .token
168	            .clone()
169	            .unwrap_or_default();
170	        spawn(async move {
171	            // Best-effort server-side logout — even if the call fails
172	            // (e.g. already-expired token), we still clear local state.
173	            let _ = auth::logout(&token).await;
174	            auth_state.set(AuthState::default());
175	            AuthState::clear_storage();
176	            navigator.push(AppRoute::Login {});
177	        });
178	    };
179	
180	    rsx! {
181	        div { class: "app-shell",
182	            // ── Sidebar ──────────────────────────────────────
183	            nav { class: "sidebar",
184	                div { class: "sidebar__brand", "Scholarly" }
185	
186	                div { class: "sidebar__nav",
187	                    for item in nav_items.iter() {
188	                        if role_has_access(&current_role, &item.required_role) {
189	                            if let Some(section) = item.section {
190	                                div { class: "sidebar__section-title", "{section}" }
191	                            }
192	
193	                            Link {
194	                                class: "sidebar__link",
195	                                to: item.route.clone(),
196	                                "{item.label}"
197	                            }
198	                        }
199	                    }
200	                }
201	            }
202	
203	            // ── Main column ──────────────────────────────────
204	            div { class: "app-shell__main",
205	                header { class: "topbar",
206	                    div { class: "topbar__brand", "Scholarly" }
207	                    div { class: "topbar__user",
208	                        span { class: "topbar__user-name", "{display_name}" }
209	                        span {
210	                            class: "role-badge",
211	                            "data-role": "{current_role.as_snake()}",
212	                            "{current_role}"
213	                        }
214	                        button {
215	                            class: "topbar__logout",
216	                            r#type: "button",
217	                            onclick: on_logout,
218	                            "Log out"
219	                        }
220	                    }
221	                }
222	
223	                main { class: "main-content",
224	                    Outlet::<AppRoute> {}
225	                }
226	            }
227	        }
228	    }
229	}
