1	//! Application state definitions for the Scholarly frontend.
2	//!
3	//! These structs are intended to be provided as Dioxus context values
4	//! at the app root so that any component can access shared state.
5	
6	use js_sys::Date;
7	use serde::{Deserialize, Serialize};
8	use wasm_bindgen::JsValue;
9	
10	use crate::types::{Role, User};
11	
12	/// Key used to persist [`AuthState`] in browser `localStorage`.
13	const STORAGE_KEY: &str = "scholarly_auth";
14	
15	/// Authentication state — tracks the currently logged-in user and their
16	/// bearer token.
17	#[derive(Clone, Debug, Default, Serialize, Deserialize, PartialEq)]
18	pub struct AuthState {
19	    /// The authenticated user, if any.
20	    pub user: Option<User>,
21	    /// JWT or opaque bearer token for API requests.
22	    pub token: Option<String>,
23	    /// RFC3339 timestamp at which the current token expires.
24	    pub expires_at: Option<String>,
25	}
26	
27	impl AuthState {
28	    /// Returns `true` if a user is currently authenticated.
29	    ///
30	    /// Requires both a bearer token and a hydrated user record.  Also
31	    /// validates the stored `expires_at` timestamp so that a stale session
32	    /// in localStorage redirects to login immediately rather than waiting
33	    /// for the first failing API call.
34	    pub fn is_authenticated(&self) -> bool {
35	        if self.token.is_none() || self.user.is_none() {
36	            return false;
37	        }
38	        // If we have an expiry timestamp, reject tokens that are already past
39	        // their expiry time according to the browser clock.  A NaN result from
40	        // `get_time()` (invalid date string) is treated as "not expired" —
41	        // the backend session validation will catch the edge case.
42	        if let Some(ref exp) = self.expires_at {
43	            let expires_ms = Date::new(&JsValue::from_str(exp)).get_time();
44	            let now_ms = Date::now();
45	            if !expires_ms.is_nan() && now_ms >= expires_ms {
46	                return false;
47	            }
48	        }
49	        true
50	    }
51	
52	    /// Returns the user's highest-privileged role, if any.
53	    pub fn primary_role(&self) -> Option<Role> {
54	        let user = self.user.as_ref()?;
55	        user.roles
56	            .iter()
57	            .max_by_key(|r| r.level())
58	            .cloned()
59	    }
60	
61	    /// Attempts to hydrate an [`AuthState`] from `localStorage`.
62	    ///
63	    /// Returns [`AuthState::default`] on any failure (missing window,
64	    /// unavailable storage, missing key, malformed JSON).
65	    pub fn load_from_storage() -> AuthState {
66	        let storage = match web_sys::window().and_then(|w| w.local_storage().ok().flatten()) {
67	            Some(s) => s,
68	            None => return AuthState::default(),
69	        };
70	
71	        let raw = match storage.get_item(STORAGE_KEY) {
72	            Ok(Some(s)) => s,
73	            _ => return AuthState::default(),
74	        };
75	
76	        serde_json::from_str::<AuthState>(&raw).unwrap_or_default()
77	    }
78	
79	    /// Persists this [`AuthState`] into `localStorage`. All errors are
80	    /// swallowed — persistence is best-effort.
81	    pub fn save_to_storage(&self) {
82	        let Some(storage) = web_sys::window().and_then(|w| w.local_storage().ok().flatten()) else {
83	            return;
84	        };
85	        if let Ok(json) = serde_json::to_string(self) {
86	            let _ = storage.set_item(STORAGE_KEY, &json);
87	        }
88	    }
89	
90	    /// Removes the persisted auth state from `localStorage`.
91	    pub fn clear_storage() {
92	        if let Some(storage) = web_sys::window().and_then(|w| w.local_storage().ok().flatten()) {
93	            let _ = storage.remove_item(STORAGE_KEY);
94	        }
95	    }
96	}
97	
98	/// Global application state — holds non-auth concerns shared across the
99	/// app (e.g., theme preference, feature flags).
100	#[derive(Clone, Debug, Default, Serialize, Deserialize, PartialEq)]
101	pub struct AppState {
102	    /// Whether the sidebar is collapsed.
103	    pub sidebar_collapsed: bool,
104	}
