266	pub async fn get_report(pool: &MySqlPool, principal: &Principal, id: Uuid) -> AppResult<ReportView> {
267	    require(principal, Capability::ReportRead)?;
268	    let row = report_repo::find_by_id(pool, id).await?;
269	    // Enforce department scope: callers who are not Admin/Librarian may only
270	    // see reports created by users in their own department.
271	    let scope = content_scope(principal);
272	    let created_by_uuid = row.created_by.as_deref().and_then(|s| Uuid::parse_str(s).ok());
273	    let creator_dept = creator_department(pool, row.created_by.as_deref()).await?;
274	    require_object_visible(&scope, created_by_uuid, creator_dept)?;
275	    row_to_report_view(&row)
276	}
