278	pub async fn create_report(
279	    pool: &MySqlPool,
280	    principal: &Principal,
281	    input: CreateReportInput,
282	) -> AppResult<ReportView> {
283	    require(principal, Capability::ReportManage)?;
284	
285	    if input.title.trim().is_empty() {
286	        return Err(AppError::Validation("title must not be empty".to_string()));
287	    }
288	
289	    let id = Uuid::new_v4();
290	    let now = Utc::now().naive_utc();
291	    let format = input.default_format.unwrap_or(ReportFormat::Csv);
292	    let qd_json = serde_json::to_string(&input.query_definition)
293	        .map_err(|e| AppError::Internal(format!("serialize query_definition: {}", e)))?;
294	
295	    let row = ReportRow {
296	        id: id.to_string(),
297	        title: input.title.clone(),
298	        description: input.description.clone(),
299	        query_definition: qd_json,
300	        default_format: format.as_db().to_string(),
301	        created_by: Some(principal.user_id.to_string()),
302	        created_at: now,
303	        updated_at: now,
304	    };
305	
306	    report_repo::insert(pool, &row).await?;
307	
308	    audit_service::record(
309	        pool,
310	        AuditEvent {
311	            actor_id: Some(principal.user_id),
312	            actor_email: Some(&principal.email),
313	            action: actions::REPORT_CREATE,
314	            target_entity_type: Some("report"),
315	            target_entity_id: Some(id),
316	            change_payload: Some(serde_json::json!({ "title": input.title })),
317	            ip_address: None,
318	            user_agent: None,
319	        },
320	    )
321	    .await?;
322	
323	    let created = report_repo::find_by_id(pool, id).await?;
324	    row_to_report_view(&created)
325	}
