327	pub async fn update_report(
328	    pool: &MySqlPool,
329	    principal: &Principal,
330	    id: Uuid,
331	    input: UpdateReportInput,
332	) -> AppResult<ReportView> {
333	    require(principal, Capability::ReportManage)?;
334	
335	    let existing = report_repo::find_by_id(pool, id).await?;
336	
337	    let new_title = input.title.as_deref().unwrap_or(&existing.title);
338	    if new_title.trim().is_empty() {
339	        return Err(AppError::Validation("title must not be empty".to_string()));
340	    }
341	
342	    let new_description = match &input.description {
343	        Some(d) => Some(d.as_str()),
344	        None => existing.description.as_deref(),
345	    };
346	
