1	//! Response masking utilities for sensitive fields.
2	//!
3	//! The masking framework is deliberately explicit: every callsite that
4	//! returns possibly-sensitive data must pass its value through a masking
5	//! function. There is no implicit serde-time magic; a reviewer can grep
6	//! for `mask_` and see every redaction point.
7	//!
8	//! Current redaction rules (Phase 2):
9	//!
10	//! | Field                   | Visible to                                    |
11	//! |-------------------------|-----------------------------------------------|
12	//! | student identifier      | Admin, Instructor (their own section), DeptHead |
13	//! | instructor notes        | Admin, the instructor that wrote them          |
14	//! | actor email (audit log) | Admin only; others see a hashed prefix         |
15	//! | ip address (audit log)  | Admin only                                     |
16	//!
17	//! Object-level scope (who "their own section" is) is handled by
18	//! [`crate::application::scope`]; this module only answers the binary
19	//! "mask or not?" question given a capability gate.
20	
21	use super::principal::{Principal, Role};
22	use sha2::{Digest, Sha256};
23	
24	/// Generic masking helper: returns the original or `"[REDACTED]"`.
25	pub fn mask_if(value: &str, visible: bool) -> String {
26	    if visible {
27	        value.to_string()
28	    } else {
29	        "[REDACTED]".to_string()
30	    }
31	}
32	
33	/// Mask an email for non-admin audit viewers.
34	///
35	/// Non-admins see a deterministic 8-char prefix of SHA-256(email) so the
36	/// audit log is still useful for correlation without leaking the identity.
37	pub fn mask_email_for_audit(email: &str, viewer: &Principal) -> String {
38	    if viewer.is_admin() {
39	        return email.to_string();
40	    }
41	    let digest = Sha256::digest(email.as_bytes());
42	    let hex = hex::encode(digest);
43	    format!("user:{}", &hex[..8])
44	}
