149	/// Append a new audit event. Writes two rows atomically via a transaction.
150	pub async fn record(pool: &MySqlPool, event: AuditEvent<'_>) -> AppResult<Uuid> {
151	    let mut tx = pool
152	        .begin()
153	        .await
154	        .map_err(|e| AppError::Database(format!("audit tx begin: {}", e)))?;
155	
156	    let audit_id = Uuid::new_v4();
157	    let payload_json = event.change_payload.as_ref().map(|v| {
158	        serde_json::to_string(v).unwrap_or_else(|e| {
159	            tracing::warn!(
160	                action = event.action,
161	                "failed to serialize audit change_payload, storing null: {}",
162	                e
163	            );
164	            "null".into()
165	        })
166	    });
167	
168	    sqlx::query(
169	        r#"
170	        INSERT INTO audit_logs
171	            (id, actor_id, actor_email, action,
172	             target_entity_type, target_entity_id,
173	             change_payload, ip_address, user_agent)
174	        VALUES (?, ?, ?, ?, ?, ?, CAST(? AS JSON), ?, ?)
175	        "#,
176	    )
177	    .bind(audit_id.to_string())
178	    .bind(event.actor_id.map(|u| u.to_string()))
179	    .bind(event.actor_email)
180	    .bind(event.action)
181	    .bind(event.target_entity_type)
182	    .bind(event.target_entity_id.map(|u| u.to_string()))
183	    .bind(payload_json.as_deref().unwrap_or("null"))
184	    .bind(event.ip_address)
185	    .bind(event.user_agent)
186	    .execute(&mut *tx)
187	    .await
188	    .map_err(|e| AppError::Database(format!("audit_logs insert: {}", e)))?;
189	
190	    // Obtain the previous chain tip under the same transaction so concurrent
191	    // writers can't collide on sequence_number.
192	    let tip_row = sqlx::query(
193	        r#"
194	        SELECT sequence_number, current_hash
195	          FROM audit_hash_chain
196	         ORDER BY sequence_number DESC
197	         LIMIT 1 FOR UPDATE
198	        "#,
199	    )
200	    .fetch_optional(&mut *tx)
201	    .await
202	    .map_err(|e| AppError::Database(format!("audit tip read: {}", e)))?;
203	
204	    let (prev_seq, prev_hash): (i64, Option<String>) = match tip_row {
205	        None => (0, None),
206	        Some(row) => {
207	            let seq: i64 = row
208	                .try_get("sequence_number")
209	                .map_err(|e| AppError::Database(e.to_string()))?;
210	            let hash: String = row
211	                .try_get("current_hash")
212	                .map_err(|e| AppError::Database(e.to_string()))?;
213	            (seq, Some(hash))
214	        }
215	    };
216	    let sequence = prev_seq + 1;
217	
218	    let current_hash = compute_hash(
219	        prev_hash.as_deref(),
220	        sequence,
221	        audit_id,
222	        event.action,
223	        payload_json.as_deref(),
224	    );
225	
226	    sqlx::query(
227	        r#"
228	        INSERT INTO audit_hash_chain
229	            (id, audit_log_id, sequence_number, previous_hash, current_hash)
230	        VALUES (?, ?, ?, ?, ?)
231	        "#,
232	    )
233	    .bind(Uuid::new_v4().to_string())
234	    .bind(audit_id.to_string())
235	    .bind(sequence)
236	    .bind(prev_hash)
237	    .bind(&current_hash)
238	    .execute(&mut *tx)
239	    .await
240	    .map_err(|e| AppError::Database(format!("audit_hash_chain insert: {}", e)))?;
241	
242	    tx.commit()
243	        .await
244	        .map_err(|e| AppError::Database(format!("audit tx commit: {}", e)))?;
245	
246	    Ok(audit_id)
247	}
248	
249	/// Compute the SHA-256 hex digest for a chain entry.
250	///
251	/// The input layout is `previous_hash || 0x7c || sequence || 0x7c ||
252	/// audit_id || 0x7c || action || 0x7c || payload`. `0x7c` is `|`, used as
253	/// an unambiguous field separator. Exposed so unit tests can reproduce
254	/// the exact bytes.
255	pub fn compute_hash(
256	    previous_hash: Option<&str>,
257	    sequence_number: i64,
258	    audit_log_id: Uuid,
259	    action: &str,
260	    payload_json: Option<&str>,
261	) -> String {
262	    let mut hasher = Sha256::new();
263	    hasher.update(previous_hash.unwrap_or("").as_bytes());
264	    hasher.update(b"|");
265	    hasher.update(sequence_number.to_be_bytes());
266	    hasher.update(b"|");
267	    hasher.update(audit_log_id.as_bytes());
268	    hasher.update(b"|");
269	    hasher.update(action.as_bytes());
270	    hasher.update(b"|");
271	    hasher.update(payload_json.unwrap_or("null").as_bytes());
272	    hex::encode(hasher.finalize())
273	}
274	
275	/// Walk the entire chain in sequence order and verify every link.
276	pub async fn verify_chain(pool: &MySqlPool) -> AppResult<ChainStatus> {
277	    let rows = sqlx::query(
278	        r#"
279	        SELECT c.sequence_number, c.previous_hash, c.current_hash,
280	               c.audit_log_id, l.action,
281	               CAST(l.change_payload AS CHAR) AS payload_text
282	          FROM audit_hash_chain c
283	          JOIN audit_logs       l ON l.id = c.audit_log_id
284	         ORDER BY c.sequence_number ASC
285	        "#,
286	    )
287	    .fetch_all(pool)
288	    .await
289	    .map_err(|e| AppError::Database(format!("verify_chain: {}", e)))?;
290	
291	    let mut expected_prev: Option<String> = None;
292	    let mut expected_seq: i64 = 1;
293	    let total = rows.len() as i64;
294	
295	    for row in rows {
296	        let seq: i64 = row
297	            .try_get("sequence_number")
298	            .map_err(|e| AppError::Database(e.to_string()))?;
299	        let prev: Option<String> = row
300	            .try_get("previous_hash")
301	            .map_err(|e| AppError::Database(e.to_string()))?;
302	        let curr: String = row
303	            .try_get("current_hash")
304	            .map_err(|e| AppError::Database(e.to_string()))?;
305	        let audit_id_str: String = row
306	            .try_get("audit_log_id")
307	            .map_err(|e| AppError::Database(e.to_string()))?;
308	        let action: String = row
309	            .try_get("action")
310	            .map_err(|e| AppError::Database(e.to_string()))?;
311	        let payload: Option<String> = row
312	            .try_get("payload_text")
313	            .map_err(|e| AppError::Database(e.to_string()))?;
314	
315	        if seq != expected_seq {
316	            return Ok(ChainStatus {
317	                total_entries: total,
318	                valid: false,
319	                broken_at_sequence: Some(seq),
320	                message: format!("sequence gap: expected {} got {}", expected_seq, seq),
321	            });
322	        }
323	        if prev != expected_prev {
324	            return Ok(ChainStatus {
325	                total_entries: total,
326	                valid: false,
327	                broken_at_sequence: Some(seq),
328	                message: format!("previous_hash mismatch at sequence {}", seq),
329	            });
330	        }
331	        let audit_uuid = Uuid::parse_str(&audit_id_str)
332	            .map_err(|e| AppError::Database(e.to_string()))?;
333	        let recomputed = compute_hash(
334	            expected_prev.as_deref(),
335	            seq,
336	            audit_uuid,
337	            &action,
338	            payload.as_deref(),
339	        );
340	        if recomputed != curr {
341	            return Ok(ChainStatus {
342	                total_entries: total,
343	                valid: false,
344	                broken_at_sequence: Some(seq),
345	                message: format!("current_hash mismatch at sequence {}", seq),
346	            });
347	        }
348	        expected_prev = Some(curr);
349	        expected_seq += 1;
350	    }
351	
352	    Ok(ChainStatus {
353	        total_entries: total,
354	        valid: true,
355	        broken_at_sequence: None,
356	        message: "chain verified".into(),
357	    })
358	}
