360	/// Paginated audit search. Callers must have already passed
361	/// `Capability::AuditRead`. Masking is applied by the caller via
362	/// [`crate::application::masking`] before the rows go over the wire.
363	pub async fn search(pool: &MySqlPool, filter: &AuditSearch) -> AppResult<Vec<AuditLogView>> {
364	    // Cap the limit server-side no matter what the client asked for.
365	    let limit = filter.limit.clamp(1, 500) as i64;
366	
367	    let mut sql = String::from(
368	        r#"
369	        SELECT l.id, c.sequence_number, l.actor_id, l.actor_email, l.action,
370	               l.target_entity_type, l.target_entity_id, l.ip_address,
371	               l.created_at, c.current_hash
372	          FROM audit_logs l
373	          JOIN audit_hash_chain c ON c.audit_log_id = l.id
374	         WHERE 1=1
375	        "#,
376	    );
377	    if filter.actor_id.is_some() {
378	        sql.push_str(" AND l.actor_id = ?");
379	    }
380	    if filter.action.is_some() {
381	        sql.push_str(" AND l.action = ?");
382	    }
383	    if filter.target_entity_type.is_some() {
384	        sql.push_str(" AND l.target_entity_type = ?");
385	    }
386	    if filter.target_entity_id.is_some() {
387	        sql.push_str(" AND l.target_entity_id = ?");
388	    }
389	    if filter.from.is_some() {
390	        sql.push_str(" AND l.created_at >= ?");
391	    }
392	    if filter.to.is_some() {
393	        sql.push_str(" AND l.created_at <= ?");
394	    }
395	    sql.push_str(" ORDER BY c.sequence_number DESC LIMIT ?");
396	
397	    let mut q = sqlx::query(&sql);
398	    if let Some(id) = filter.actor_id {
399	        q = q.bind(id.to_string());
400	    }
401	    if let Some(ref a) = filter.action {
402	        q = q.bind(a.clone());
403	    }
404	    if let Some(ref t) = filter.target_entity_type {
405	        q = q.bind(t.clone());
406	    }
407	    if let Some(id) = filter.target_entity_id {
408	        q = q.bind(id.to_string());
409	    }
410	    if let Some(from) = filter.from {
411	        q = q.bind(from.naive_utc());
412	    }
413	    if let Some(to) = filter.to {
414	        q = q.bind(to.naive_utc());
415	    }
416	    q = q.bind(limit);
417	
418	    let rows = q
419	        .fetch_all(pool)
420	        .await
421	        .map_err(|e| AppError::Database(format!("audit search: {}", e)))?;
422	
423	    let mut out = Vec::with_capacity(rows.len());
424	    for row in rows {
425	        let id: String = row
426	            .try_get("id")
427	            .map_err(|e| AppError::Database(e.to_string()))?;
428	        let seq: i64 = row
429	            .try_get("sequence_number")
430	            .map_err(|e| AppError::Database(e.to_string()))?;
431	        let actor_id: Option<String> = row
432	            .try_get("actor_id")
433	            .map_err(|e| AppError::Database(e.to_string()))?;
434	        let actor_email: Option<String> = row
435	            .try_get("actor_email")
436	            .map_err(|e| AppError::Database(e.to_string()))?;
437	        let action: String = row
438	            .try_get("action")
439	            .map_err(|e| AppError::Database(e.to_string()))?;
440	        let target_entity_type: Option<String> = row
441	            .try_get("target_entity_type")
442	            .map_err(|e| AppError::Database(e.to_string()))?;
443	        let target_entity_id: Option<String> = row
444	            .try_get("target_entity_id")
445	            .map_err(|e| AppError::Database(e.to_string()))?;
446	        let ip_address: Option<String> = row
447	            .try_get("ip_address")
448	            .map_err(|e| AppError::Database(e.to_string()))?;
