3	use std::io::Cursor;
4	
5	use rocket::http::{ContentType, Status};
6	use rocket::response::{self, Responder, Response};
7	use rocket::Request;
8	
9	/// A streamed byte payload with an explicit MIME type and download filename.
10	pub struct BinaryDownload {
11	    pub bytes: Vec<u8>,
12	    pub mime: &'static str,
13	    pub filename: String,
14	}
15	
16	impl<'r> Responder<'r, 'static> for BinaryDownload {
17	    fn respond_to(self, _req: &'r Request<'_>) -> response::Result<'static> {
18	        let content_type = ContentType::parse_flexible(self.mime)
19	            .unwrap_or(ContentType::Binary);
20	        // ASCII-strip the filename for the Content-Disposition header.
21	        let safe_name: String = self
22	            .filename
23	            .chars()
24	            .filter(|c| c.is_ascii() && !c.is_control())
25	            .collect();
26	        Response::build()
27	            .status(Status::Ok)
28	            .header(content_type)
29	            .raw_header(
30	                "Content-Disposition",
31	                format!("attachment; filename=\"{}\"", safe_name),
32	            )
33	            .sized_body(self.bytes.len(), Cursor::new(self.bytes))
34	            .ok()
35	    }
36	}
