98	/// GET /api/v1/audit-logs/export.csv?actor_id=&action=&from=&to=&limit=
99	///
100	/// Export audit log entries as a UTF-8 CSV file.
101	///
102	/// Requires `Capability::AuditExport` (Admin-only per the current capability
103	/// matrix). Masking rules are applied identically to the JSON listing endpoint
104	/// so the same email-hash and IP-redaction policies hold. The export is itself
105	/// recorded in the audit log as an `audit.export` event.
106	///
107	/// Response headers:
108	/// - `Content-Type: text/csv; charset=utf-8`
109	/// - `Content-Disposition: attachment; filename="audit_logs_<YYYYMMDD_HHMMSS>.csv"`
110	///
111	/// Default limit for export is 500 (server-capped maximum). Pass `limit=` to
112	/// reduce the window. Supports all the same filter parameters as
113	/// `GET /api/v1/audit-logs`.
114	#[get("/export.csv?<actor_id>&<action>&<target_entity_type>&<target_entity_id>&<from>&<to>&<limit>")]
115	pub async fn export_csv(
116	    principal: AuthedPrincipal,
117	    pool: &State<MySqlPool>,
118	    actor_id: Option<String>,
119	    action: Option<String>,
120	    target_entity_type: Option<String>,
121	    target_entity_id: Option<String>,
122	    from: Option<String>,
123	    to: Option<String>,
124	    limit: Option<u32>,
125	) -> AppResult<BinaryDownload> {
126	    let principal = principal.into_inner();
127	    authorization::require(&principal, Capability::AuditExport)?;
128	
129	    let filter = AuditSearch {
130	        actor_id: parse_uuid_opt(actor_id.as_deref(), "actor_id")?,
131	        action,
132	        target_entity_type,
133	        target_entity_id: parse_uuid_opt(target_entity_id.as_deref(), "target_entity_id")?,
134	        from: parse_rfc3339_opt(from.as_deref(), "from")?,
135	        to: parse_rfc3339_opt(to.as_deref(), "to")?,
136	        // Default to the server-capped maximum for exports; callers may lower it.
137	        limit: limit.unwrap_or(500),
138	    };
139	
140	    let mut entries = audit_service::search(pool.inner(), &filter).await?;
141	
142	    // Apply the same masking rules as the JSON listing endpoint so that
143	    // non-admin callers (if AuditExport is ever extended to Auditor) still
144	    // see hashed emails and redacted IPs.
145	    for row in entries.iter_mut() {
146	        if let Some(ref email) = row.actor_email {
147	            row.actor_email = Some(masking::mask_email_for_audit(email, &principal));
148	        }
149	        row.ip_address = masking::mask_ip_for_audit(row.ip_address.as_deref(), &principal);
150	    }
151	
152	    // Record the export to the audit log (best-effort; do not fail the export).
153	    let _ = audit_service::record(
154	        pool.inner(),
155	        AuditEvent {
156	            actor_id: Some(principal.user_id),
157	            actor_email: Some(&principal.email),
158	            action: actions::AUDIT_EXPORT,
159	            target_entity_type: Some("audit_log"),
160	            target_entity_id: None,
161	            change_payload: Some(serde_json::json!({
162	                "row_count": entries.len(),
163	                "filter": {
164	                    "actor_id": filter.actor_id,
165	                    "action": filter.action,
166	                    "target_entity_type": filter.target_entity_type,
167	                    "from": filter.from,
168	                    "to": filter.to,
169	                }
170	            })),
171	            ip_address: None,
172	            user_agent: None,
173	        },
174	    )
175	    .await;
176	
177	    let bytes = audit_service::export_to_csv(&entries);
178	    let filename = format!(
179	        "audit_logs_{}.csv",
180	        chrono::Utc::now().format("%Y%m%d_%H%M%S"),
181	    );
182	
183	    Ok(BinaryDownload {
184	        bytes,
185	        mime: "text/csv; charset=utf-8",
186	        filename,
187	    })
188	}
