190	/// GET /api/v1/audit-logs/verify-chain — admin-only chain integrity check.
191	#[get("/verify-chain")]
192	pub async fn verify_chain_endpoint(
193	    admin: AdminOnly,
194	    pool: &State<MySqlPool>,
195	) -> AppResult<Json<ChainStatus>> {
196	    let admin = admin.into_inner();
197	    let status = audit_service::verify_chain(pool.inner()).await?;
198	
199	    let _ = audit_service::record(
200	        pool.inner(),
201	        AuditEvent {
202	            actor_id: Some(admin.user_id),
203	            actor_email: Some(&admin.email),
204	            action: actions::AUDIT_CHAIN_VERIFY,
205	            target_entity_type: Some("audit_chain"),
206	            target_entity_id: None,
207	            change_payload: Some(serde_json::json!({
208	                "total_entries": status.total_entries,
209	                "valid": status.valid,
210	                "broken_at_sequence": status.broken_at_sequence,
211	            })),
212	            ip_address: None,
213	            user_agent: None,
214	        },
215	    )
216	    .await;
217	
218	    Ok(Json(status))
219	}
220	
221	fn parse_uuid_opt(raw: Option<&str>, field: &str) -> AppResult<Option<Uuid>> {
222	    match raw {
223	        None => Ok(None),
224	        Some(s) if s.is_empty() => Ok(None),
225	        Some(s) => Uuid::parse_str(s)
226	            .map(Some)
227	            .map_err(|_| AppError::Validation(format!("{} must be a UUID", field))),
228	    }
229	}
230	
231	fn parse_rfc3339_opt(raw: Option<&str>, field: &str) -> AppResult<Option<DateTime<Utc>>> {
232	    match raw {
233	        None => Ok(None),
234	        Some(s) if s.is_empty() => Ok(None),
235	        Some(s) => DateTime::parse_from_rfc3339(s)
236	            .map(|d| Some(d.with_timezone(&Utc)))
237	            .map_err(|_| AppError::Validation(format!("{} must be RFC3339", field))),
238	    }
239	}
