128	// ---------------------------------------------------------------------------
129	// Layout component
130	// ---------------------------------------------------------------------------
131	
132	/// Main layout component rendered around all authenticated routes.
133	///
134	/// Provides the top bar, sidebar navigation, and a content area that is
135	/// filled by the active child route via `Outlet`.
136	#[component]
137	pub fn MainLayout() -> Element {
138	    let mut auth_state = use_context::<Signal<AuthState>>();
139	    let navigator = use_navigator();
140	
141	    // Redirect unauthenticated visitors to /login. Running the push
142	    // inside `use_effect` avoids mutating the router during rendering.
143	    let authed = auth_state.read().is_authenticated();
144	    use_effect(move || {
145	        if !auth_state.read().is_authenticated() {
146	            navigator.push(AppRoute::Login {});
147	        }
148	    });
149	
150	    if !authed {
151	        // Render an empty placeholder while the effect pushes the
152	        // user to the login page on the next tick.
153	        return rsx! { div {} };
154	    }
155	
156	    let snapshot = auth_state.read().clone();
157	    let current_role = snapshot.primary_role().unwrap_or(Role::Viewer);
158	    let display_name = snapshot
159	        .user
160	        .as_ref()
161	        .map(|u| u.display_name.clone())
162	        .unwrap_or_else(|| "Unknown user".to_string());
163	
164	    let nav_items = navigation_items();
165	
166	    let on_logout = move |_| {
167	        let token = auth_state
168	            .read()
169	            .token
170	            .clone()
171	            .unwrap_or_default();
172	        spawn(async move {
173	            // Best-effort server-side logout — even if the call fails
174	            // (e.g. already-expired token), we still clear local state.
175	            let _ = auth::logout(&token).await;
176	            auth_state.set(AuthState::default());
177	            AuthState::clear_storage();
178	            navigator.push(AppRoute::Login {});
179	        });
180	    };
181	
182	    rsx! {
183	        div { class: "app-shell",
184	            // ── Sidebar ──────────────────────────────────────
185	            nav { class: "sidebar",
186	                div { class: "sidebar__brand", "Scholarly" }
187	
188	                div { class: "sidebar__nav",
189	                    for item in nav_items.iter() {
190	                        if role_has_access(&current_role, &item.required_role) {
191	                            if let Some(section) = item.section {
192	                                div { class: "sidebar__section-title", "{section}" }
193	                            }
194	
195	                            Link {
196	                                class: "sidebar__link",
197	                                to: item.route.clone(),
198	                                "{item.label}"
199	                            }
200	                        }
201	                    }
202	                }
203	            }
204	
205	            // ── Main column ──────────────────────────────────
206	            div { class: "app-shell__main",
207	                header { class: "topbar",
208	                    div { class: "topbar__brand", "Scholarly" }
209	                    div { class: "topbar__user",
210	                        span { class: "topbar__user-name", "{display_name}" }
211	                        span {
212	                            class: "role-badge",
213	                            "data-role": "{current_role.as_snake()}",
214	                            "{current_role}"
215	                        }
216	                        button {
217	                            class: "topbar__logout",
218	                            r#type: "button",
219	                            onclick: on_logout,
220	                            "Log out"
221	                        }
222	                    }
223	                }
224	
225	                main { class: "main-content",
226	                    Outlet::<AppRoute> {}
227	                }
228	            }
229	        }
230	    }
231	}
