        NavItem {
            label: "Courses",
            route: AppRoute::CourseList {},
            section: Some("Courses"),
        },
        // -- Operations --
        NavItem {
            label: "Import / Export",
            route: AppRoute::Imports {},
            section: Some("Operations"),
        },
        NavItem {
            label: "Check-In",
            route: AppRoute::CheckIn {},
            section: None,
        },
