1	//! Scholarly backend library crate.
2	//!
3	//! This crate exposes [`build_rocket`] so both `src/main.rs` and the
4	//! integration tests in `backend/tests/` can assemble an identical Rocket
5	//! instance.
6	
7	// Pulls in the full set of Rocket attribute macros (`#[get]`, `#[post]`,
8	// `routes!`, `catchers!`, `uri!`, etc.) crate-wide. Keeping this here
9	// avoids per-module `use rocket::{get, post, ...}` boilerplate.
10	#[macro_use]
11	extern crate rocket;
12	
13	pub mod api;
14	pub mod application;
15	pub mod config;
16	pub mod domain;
17	pub mod errors;
18	pub mod infrastructure;
19	
20	use rocket::{Build, Rocket};
21	
22	/// Assemble the full Rocket instance: connect to MySQL, run the one-time
23	/// bootstrap routine (replacing seed sentinel password hashes), initialise
24	/// field-level encryption, and mount every route namespace.
25	///
26	/// Phase 6 additions:
27	/// * `FieldEncryption` added as managed state (injected into API handlers).
28	/// * `ReportScheduler` spawned as a background Tokio task.
29	pub async fn build_rocket() -> Rocket<Build> {
30	    let app_config = config::AppConfig::from_env();
31	    tracing::info!(url = %redact_db_url(&app_config.database_url), "connecting to database");
32	
33	    let pool = infrastructure::database::init_pool(&app_config.database_url)
34	        .await
35	        .expect("database pool initialization failed");
36	
37	    // First-boot bootstrap: hash seed passwords if still sentinels.
38	    // Failure here is fatal: the process exits rather than starting with
39	    // unusable sentinel rows (which would let the service report healthy
40	    // while rejecting every login attempt).
41	    infrastructure::bootstrap::ensure_seed_passwords(&pool)
42	        .await
43	        .expect("bootstrap failed: cannot start without valid seed password hashes");
44	
45	    // Phase 6: initialise AES-256-GCM field encryption.
46	    let encryption =
47	        application::encryption::FieldEncryption::from_base64(&app_config.field_encryption_key)
48	            .expect("FIELD_ENCRYPTION_KEY must be a valid base64url-encoded 32-byte key");
49	
50	    if encryption.is_dev_key() {
51	        tracing::warn!(
52	            "FIELD_ENCRYPTION_KEY is the insecure development default. \
53	             Set a real random key in production using: \
54	             openssl rand -base64 32 | tr '+/' '-_' | tr -d '='"
55	        );
56	    }
57	
58	    // Phase 6: spawn the background report scheduler.
59	    // The scheduler polls every ~60 seconds for due report schedules and
60	    // executes them, storing generated artifact files in reports_storage_path.
61	    {
62	        let scheduler = infrastructure::scheduler::ReportScheduler::new(
63	            pool.clone(),
64	            app_config.reports_storage_path.clone(),
65	            encryption.clone(),
66	        );
67	        scheduler.spawn();
68	    }
69	
70	    rocket::build()
71	        .manage(pool)
72	        .manage(app_config)
73	        .manage(encryption)
74	        // ── Auth ──
75	        .mount("/api/v1/auth", api::auth::routes())
76	        // ── Users & RBAC ──
77	        .mount("/api/v1/users", api::users::routes())
78	        .mount("/api/v1/roles", api::roles::routes())
79	        // ── Core domains ──
80	        .mount("/api/v1/journals", api::journals::routes())
81	        .mount("/api/v1/teaching-resources", api::teaching_resources::routes())
82	        .mount("/api/v1/courses", api::courses::routes())
83	        .mount("/api/v1/sections", api::sections::routes())
84	        .mount("/api/v1/attachments", api::attachments::routes())
85	        // ── Operations ──
86	        .mount("/api/v1/checkins", api::checkins::routes())
87	        .mount("/api/v1/metrics", api::metrics::routes())
88	        .mount("/api/v1/dashboards", api::dashboards::routes())
89	        .mount("/api/v1/reports", api::reports::routes())
90	        // ── Administration ──
91	        .mount("/api/v1/audit-logs", api::audit_logs::routes())
92	        .mount("/api/v1/admin/config", api::admin_config::routes())
93	        .mount("/api/v1/admin/retention", api::retention::routes())
94	        // ── Health ──
95	        .mount("/api/v1", api::health::routes())
96	        // ── Error catchers — must be last ──
97	        .register("/", api::catchers::catchers())
98	}
99	
100	/// Strip the password from a database URL for safe logging.
101	fn redact_db_url(url: &str) -> String {
102	    // mysql://user:password@host:port/db  -> mysql://user:***@host:port/db
103	    if let Some(scheme_end) = url.find("://") {
104	        let rest = &url[scheme_end + 3..];
105	        if let Some(at) = rest.find('@') {
106	            let userpass = &rest[..at];
107	            if let Some(colon) = userpass.find(':') {
108	                let user = &userpass[..colon];
109	                let host_part = &rest[at..];
110	                return format!("{}://{}:***{}", &url[..scheme_end], user, host_part);
111	            }
112	        }
113	    }
114	    url.to_string()
115	}
116	
117	#[cfg(test)]
118	mod tests {
119	    use super::*;
120	
121	    #[test]
122	    fn redact_db_url_masks_password() {
123	        let masked = redact_db_url("mysql://user:supersecret@db:3306/scholarly");
124	        assert!(!masked.contains("supersecret"));
125	        assert!(masked.contains("user"));
126	        assert!(masked.contains("db:3306/scholarly"));
127	    }
128	
129	    #[test]
130	    fn redact_db_url_handles_missing_password() {
131	        // If the URL has no password, redaction should be a no-op.
132	        let masked = redact_db_url("mysql://db/scholarly");
133	        assert_eq!(masked, "mysql://db/scholarly");
134	    }
135	}
