1	//! Rocket request guards that back the authorization layer.
2	//!
3	//! Four guards are exported:
4	//!
5	//! * [`RequestId`] — populated unconditionally for every request so error
6	//!   envelopes always carry a correlation id. Not an auth gate on its own.
7	//! * [`ClientContext`] — extracts the client IP address and User-Agent
8	//!   into an owned struct so handlers can forward them to the audit log
9	//!   without taking a raw `&Request<'_>`.
10	//! * [`AuthedPrincipal`] — succeeds only when the request carries a valid
11	//!   `Authorization: Bearer <token>` whose opaque session is still active.
12	//! * [`AdminOnly`] — super-set of `AuthedPrincipal` that additionally
13	//!   requires `Role::Admin`.
14	//!
15	//! The pool and config are pulled from Rocket's managed state inside the
16	//! guard so handlers don't have to re-pass them.
17	
18	use rocket::http::Status;
19	use rocket::outcome::Outcome;
20	use rocket::request::{self, FromRequest, Request};
21	use rocket::State;
22	use sqlx::MySqlPool;
23	use uuid::Uuid;
24	
25	use crate::application::auth_service;
26	use crate::application::principal::{Principal, Role};
27	use crate::application::session;
28	use crate::errors::AppError;
29	
30	// ---------------------------------------------------------------------------
31	// RequestId
32	// ---------------------------------------------------------------------------
33	
34	/// Per-request correlation identifier. Put into `Request::local_cache` so
35	/// both the error responder and log lines can read it.
36	#[derive(Clone, Debug)]
37	pub struct RequestId(pub String);
38	
39	#[rocket::async_trait]
40	impl<'r> FromRequest<'r> for RequestId {
41	    type Error = std::convert::Infallible;
42	    async fn from_request(req: &'r Request<'_>) -> request::Outcome<Self, Self::Error> {
43	        let id = req
44	            .local_cache(|| RequestId(Uuid::new_v4().to_string()))
45	            .clone();
46	        Outcome::Success(id)
47	    }
48	}
49	
50	// ---------------------------------------------------------------------------
51	// ClientContext — IP address + User-Agent, owned
52	// ---------------------------------------------------------------------------
53	
54	/// Captures the ambient HTTP client context that service code needs for
55	/// audit logging and lockout tracking. Infallible — always succeeds.
56	#[derive(Debug, Clone, Default)]
57	pub struct ClientContext {
58	    pub ip_address: Option<String>,
59	    pub user_agent: Option<String>,
60	}
61	
62	#[rocket::async_trait]
63	impl<'r> FromRequest<'r> for ClientContext {
64	    type Error = std::convert::Infallible;
65	    async fn from_request(req: &'r Request<'_>) -> request::Outcome<Self, Self::Error> {
66	        // Prime the request id so error envelopes correlate even on the
67	        // unauthenticated path.
68	        let _ = req.local_cache(|| RequestId(Uuid::new_v4().to_string()));
69	        Outcome::Success(ClientContext {
70	            ip_address: request_ip(req),
71	            user_agent: request_user_agent(req),
72	        })
73	    }
74	}
75	
76	// ---------------------------------------------------------------------------
77	// AuthedPrincipal
78	// ---------------------------------------------------------------------------
79	
80	/// Authenticated principal guard.
81	///
82	/// Rejects with 401 if the Authorization header is missing or malformed,
83	/// or if the token is unknown/expired/revoked.
84	#[derive(Debug, Clone)]
85	pub struct AuthedPrincipal(pub Principal);
86	
87	impl AuthedPrincipal {
88	    pub fn into_inner(self) -> Principal {
89	        self.0
90	    }
91	    pub fn as_ref(&self) -> &Principal {
92	        &self.0
93	    }
94	}
95	
96	fn extract_bearer(req: &Request<'_>) -> Option<String> {
97	    let header = req.headers().get_one("Authorization")?;
98	    let trimmed = header.trim();
99	    if trimmed.len() > 7 && trimmed[..7].eq_ignore_ascii_case("Bearer ") {
100	        Some(trimmed[7..].trim().to_string())
101	    } else {
102	        None
103	    }
104	}
105	
106	#[rocket::async_trait]
107	impl<'r> FromRequest<'r> for AuthedPrincipal {
108	    type Error = AppError;
109	
110	    async fn from_request(req: &'r Request<'_>) -> request::Outcome<Self, Self::Error> {
111	        let _ = req.local_cache(|| RequestId(Uuid::new_v4().to_string()));
112	
113	        let Some(token) = extract_bearer(req) else {
114	            return Outcome::Error((Status::Unauthorized, AppError::Unauthorized));
115	        };
116	
117	        let pool = match req.guard::<&State<MySqlPool>>().await {
118	            Outcome::Success(p) => p,
119	            _ => {
120	                return Outcome::Error((
121	                    Status::InternalServerError,
122	                    AppError::Internal("database pool not managed".into()),
123	                ))
124	            }
125	        };
126	
127	        let session_record = match session::find_active_by_token(pool.inner(), &token).await {
128	            Ok(s) => s,
129	            Err(e) => {
130	                let status = e.status();
131	                return Outcome::Error((status, e));
132	            }
133	        };
134	
135	        match auth_service::load_principal_for_session(pool.inner(), &session_record).await {
136	            Ok(principal) => Outcome::Success(AuthedPrincipal(principal)),
137	            Err(e) => {
138	                let status = e.status();
139	                Outcome::Error((status, e))
140	            }
141	        }
142	    }
143	}
144	
145	// ---------------------------------------------------------------------------
146	// AdminOnly
147	// ---------------------------------------------------------------------------
148	
149	/// Admin-only guard. Fails with 403 if the principal is not `Role::Admin`.
150	#[derive(Debug, Clone)]
151	pub struct AdminOnly(pub Principal);
152	
153	impl AdminOnly {
154	    pub fn into_inner(self) -> Principal {
155	        self.0
156	    }
157	    pub fn as_ref(&self) -> &Principal {
158	        &self.0
159	    }
160	}
161	
162	#[rocket::async_trait]
163	impl<'r> FromRequest<'r> for AdminOnly {
164	    type Error = AppError;
165	
166	    async fn from_request(req: &'r Request<'_>) -> request::Outcome<Self, Self::Error> {
167	        match req.guard::<AuthedPrincipal>().await {
168	            Outcome::Success(inner) => {
169	                if inner.0.has_role(Role::Admin) {
170	                    Outcome::Success(AdminOnly(inner.0))
171	                } else {
172	                    Outcome::Error((Status::Forbidden, AppError::Forbidden))
173	                }
174	            }
175	            Outcome::Error(e) => Outcome::Error(e),
176	            Outcome::Forward(f) => Outcome::Forward(f),
177	        }
178	    }
179	}
180	
181	// ---------------------------------------------------------------------------
182	// Helpers
183	// ---------------------------------------------------------------------------
184	
185	pub fn request_ip(req: &Request<'_>) -> Option<String> {
186	    if let Some(xff) = req.headers().get_one("X-Forwarded-For") {
187	        if let Some(first) = xff.split(',').next() {
188	            return Some(first.trim().to_string());
189	        }
190	    }
191	    req.client_ip().map(|ip| ip.to_string())
192	}
193	
194	pub fn request_user_agent(req: &Request<'_>) -> Option<String> {
195	    req.headers().get_one("User-Agent").map(|s| s.to_string())
196	}
197

1	//! The authenticated principal — what the auth guard puts into request state
2	//! and what every authorization helper receives.
3	//!
4	//! A `Principal` is always the result of a verified bearer token on an
5	//! active session. Unauthenticated callers never get a `Principal`; they
6	//! get `AppError::Unauthorized` from the guard.
7	
8	use serde::{Deserialize, Serialize};
9	use uuid::Uuid;
10	
11	/// The fixed roles in the RBAC model. Stored in the database under
12	/// `roles.name` as lowercase snake_case.
13	#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
14	#[serde(rename_all = "snake_case")]
15	pub enum Role {
16	    Admin,
17	    Librarian,
18	    /// Cross-cutting read-only role for compliance and audit personnel.
19	    /// Grants audit log read and report read access; no write or admin
20	    /// capabilities. Level 90 — above Librarian, below Admin.
21	    Auditor,
22	    DepartmentHead,
23	    Instructor,
24	    Viewer,
25	}
26	
27	impl Role {
28	    pub fn as_db_name(self) -> &'static str {
29	        match self {
30	            Role::Admin => "admin",
31	            Role::Librarian => "librarian",
32	            Role::Auditor => "auditor",
33	            Role::DepartmentHead => "department_head",
34	            Role::Instructor => "instructor",
35	            Role::Viewer => "viewer",
36	        }
37	    }
38	
39	    pub fn from_db_name(name: &str) -> Option<Self> {
40	        match name {
41	            "admin" => Some(Role::Admin),
42	            "librarian" => Some(Role::Librarian),
43	            "auditor" => Some(Role::Auditor),
44	            "department_head" => Some(Role::DepartmentHead),
45	            "instructor" => Some(Role::Instructor),
46	            "viewer" => Some(Role::Viewer),
47	            _ => None,
48	        }
49	    }
50	
51	    /// Monotonic privilege level, used for hierarchy-style checks
52	    /// (e.g. "any role at least as privileged as Librarian").
53	    pub fn level(self) -> u8 {
54	        match self {
55	            Role::Admin => 100,
56	            Role::Auditor => 90,
57	            Role::Librarian => 80,
58	            Role::DepartmentHead => 60,
59	            Role::Instructor => 40,
60	            Role::Viewer => 20,
61	        }
62	    }
63	}
64	
65	/// Everything authorization code needs to know about the caller.
66	#[derive(Debug, Clone, Serialize)]
67	pub struct Principal {
68	    pub user_id: Uuid,
69	    pub session_id: Uuid,
70	    pub email: String,
71	    pub display_name: String,
72	    pub roles: Vec<Role>,
73	    pub department_id: Option<Uuid>,
74	}
75	
76	impl Principal {
77	    pub fn has_role(&self, role: Role) -> bool {
78	        self.roles.iter().any(|r| *r == role)
79	    }
80	
81	    pub fn is_admin(&self) -> bool {
82	        self.has_role(Role::Admin)
83	    }
84	
85	    pub fn max_role_level(&self) -> u8 {
86	        self.roles.iter().map(|r| r.level()).max().unwrap_or(0)
87	    }
88	
89	    /// True if any of the caller's roles meets the minimum level.
90	    pub fn at_least(&self, min: Role) -> bool {
91	        self.max_role_level() >= min.level()
92	    }
93	}
94	
95	#[cfg(test)]
96	mod tests {
97	    use super::*;
98	
99	    #[test]
100	    fn role_db_name_round_trips() {
101	        for r in [
102	            Role::Admin,
103	            Role::Librarian,
104	            Role::Auditor,
105	            Role::DepartmentHead,
106	            Role::Instructor,
107	            Role::Viewer,
108	        ] {
109	            assert_eq!(Role::from_db_name(r.as_db_name()), Some(r));
110	        }
111	        assert_eq!(Role::from_db_name("nope"), None);
112	    }
113	
114	    #[test]
115	    fn level_ordering_matches_privilege() {
116	        assert!(Role::Admin.level() > Role::Auditor.level());
117	        assert!(Role::Auditor.level() > Role::Librarian.level());
118	        assert!(Role::Librarian.level() > Role::DepartmentHead.level());
119	        assert!(Role::DepartmentHead.level() > Role::Instructor.level());
120	        assert!(Role::Instructor.level() > Role::Viewer.level());
121	    }
122	
123	    #[test]
124	    fn principal_at_least_respects_hierarchy() {
125	        let p = Principal {
126	            user_id: Uuid::nil(),
127	            session_id: Uuid::nil(),
128	            email: "x@y".into(),
129	            display_name: "x".into(),
130	            roles: vec![Role::Librarian],
