1	//! First-boot bootstrap routines.
2	//!
3	//! The seeds store users with `password_hash = '__BOOTSTRAP__'` so no
4	//! credential material lives in SQL files. On every startup we scan for
5	//! sentinel rows, hash the documented default password with Argon2id, and
6	//! overwrite the hash. This runs unconditionally but is idempotent: after
7	//! the first successful pass no sentinels remain and subsequent passes
8	//! are a no-op.
9	//!
10	//! The default password is documented in the README's "Default Seed Users"
11	//! section so operators know how to log in the first time.
12	
13	use sqlx::{MySqlPool, Row};
14	use uuid::Uuid;
15	
16	use crate::application::audit_service::{self, actions, AuditEvent};
17	use crate::application::password::{self, BOOTSTRAP_SENTINEL};
18	use crate::errors::{AppError, AppResult};
19	
20	/// Default password assigned to seeded users on first boot.
21	///
22	/// Must be at least [`password::MIN_PASSWORD_LENGTH`] characters. See
23	/// the README — operators are expected to rotate these immediately.
24	pub const DEFAULT_SEED_PASSWORD: &str = "ChangeMe!Scholarly2026";
25	
26	/// Replace every `__BOOTSTRAP__` sentinel in `users.password_hash` with a
27	/// real Argon2id hash of [`DEFAULT_SEED_PASSWORD`]. Returns the number of
28	/// rows updated.
29	pub async fn ensure_seed_passwords(pool: &MySqlPool) -> AppResult<u64> {
30	    let rows = sqlx::query("SELECT id, email FROM users WHERE password_hash = ?")
31	        .bind(BOOTSTRAP_SENTINEL)
32	        .fetch_all(pool)
33	        .await
34	        .map_err(|e| AppError::Database(format!("bootstrap scan: {}", e)))?;
35	
36	    if rows.is_empty() {
37	        tracing::info!("bootstrap: no sentinel rows, skipping");
38	        return Ok(0);
39	    }
40	
41	    let mut updated = 0u64;
42	    for row in rows {
43	        let id: String = row
44	            .try_get("id")
45	            .map_err(|e| AppError::Database(e.to_string()))?;
46	        let email: String = row
47	            .try_get("email")
48	            .map_err(|e| AppError::Database(e.to_string()))?;
49	
50	        // Fresh hash per row (unique salt per user).
51	        let hash = password::hash_password(DEFAULT_SEED_PASSWORD)?;
52	        sqlx::query("UPDATE users SET password_hash = ? WHERE id = ?")
53	            .bind(&hash)
54	            .bind(&id)
55	            .execute(pool)
56	            .await
57	            .map_err(|e| AppError::Database(format!("bootstrap update: {}", e)))?;
58	        updated += 1;
59	
60	        // Every bootstrap write is audited. The user_id is the subject.

1	//! Object-level authorization helpers.
2	//!
3	//! Separates policy from SQL. Service code calls these helpers to derive a
4	//! [`ScopeFilter`] describing which rows the principal may see, and the
5	//! repository layer translates it into a `WHERE` clause.
6	//!
7	//! Design intent: *nothing* in a route handler should hand-roll a
8	//! "if role == X then filter by Y" branch. All such decisions live here
9	//! and are unit-tested without a database.
10	
11	use uuid::Uuid;
12	
13	use super::principal::{Principal, Role};
14	use crate::errors::{AppError, AppResult};
15	
16	/// A repository-agnostic description of which rows the caller may access.
17	#[derive(Debug, Clone, PartialEq, Eq)]
18	pub enum ScopeFilter {
19	    /// Unrestricted — the caller sees every row the domain exposes.
20	    All,
21	    /// Only rows whose `department_id` matches the caller's department.
22	    Department(Uuid),
23	    /// Only rows the caller personally owns (`owner_id == user_id`).
24	    OwnedBy(Uuid),
25	    /// Union of the above two: caller's department OR caller's own.
26	    DepartmentOrOwned { department_id: Uuid, owner_id: Uuid },
27	    /// Deny everything.
28	    None,
29	}
30	
31	/// Derive the default content scope for a principal.
32	///
33	/// Rules (Phase 2):
34	/// * Admin sees everything.
35	/// * Librarian sees everything (library is institution-wide).
36	/// * Department Head sees rows in their department.
37	/// * Instructor sees their department's rows and anything they own.
38	/// * Viewer sees their department's rows only.
39	pub fn content_scope(principal: &Principal) -> ScopeFilter {
40	    if principal.is_admin() || principal.has_role(Role::Librarian) {
41	        return ScopeFilter::All;
42	    }
43	    match (principal.department_id, principal.has_role(Role::Instructor)) {
44	        (Some(dept), true) => ScopeFilter::DepartmentOrOwned {
45	            department_id: dept,
46	            owner_id: principal.user_id,
47	        },
48	        (Some(dept), false) => ScopeFilter::Department(dept),
49	        (None, true) => ScopeFilter::OwnedBy(principal.user_id),
50	        (None, false) => ScopeFilter::None,
51	    }
52	}
53	
54	/// Assert that the given object is visible to the principal under `scope`.
55	///
56	/// `owner_id` and `department_id` are the object's attributes. Used by
57	/// service methods that fetch a row by id and then verify visibility
58	/// before returning it.
59	pub fn require_object_visible(
60	    scope: &ScopeFilter,
61	    object_owner_id: Option<Uuid>,
62	    object_department_id: Option<Uuid>,
63	) -> AppResult<()> {
64	    match scope {
65	        ScopeFilter::All => Ok(()),
66	        ScopeFilter::None => Err(AppError::Forbidden),
67	        ScopeFilter::Department(dept) => {
68	            if object_department_id == Some(*dept) {
69	                Ok(())
70	            } else {
71	                Err(AppError::Forbidden)
72	            }
73	        }
74	        ScopeFilter::OwnedBy(uid) => {
75	            if object_owner_id == Some(*uid) {
76	                Ok(())
77	            } else {
78	                Err(AppError::Forbidden)
79	            }
80	        }
81	        ScopeFilter::DepartmentOrOwned {
82	            department_id,
83	            owner_id,
84	        } => {
85	            if object_department_id == Some(*department_id)
86	                || object_owner_id == Some(*owner_id)
87	            {
88	                Ok(())
89	            } else {
90	                Err(AppError::Forbidden)
91	            }
92	        }
93	    }
