1	//! Health check endpoint — liveness and readiness probe.
2	//!
3	//! `GET /health` — no authentication required. Returns a JSON object
4	//! indicating whether the server process is alive and whether the database
5	//! connection pool can reach the database.
6	//!
7	//! Expected response shapes:
8	//!
9	//! ```json
10	//! { "status": "ok",       "database": "ok"    }
11	//! { "status": "degraded", "database": "error", "message": "..." }
12	//! ```
13	//!
14	//! The HTTP status code is 200 in both cases so that load-balancer liveness
15	//! probes don't restart the container just because the DB is briefly
16	//! unavailable. Orchestration layers that care about full readiness should
17	//! inspect the `status` field.
18	
19	use rocket::serde::json::Json;
20	use rocket::State;
21	use serde::Serialize;
22	use serde_json::Value;
23	use sqlx::MySqlPool;
24	
25	pub fn routes() -> Vec<rocket::Route> {
26	    routes![health_check]
27	}
28	
29	#[derive(Serialize)]
30	pub struct HealthResponse {
31	    pub status: &'static str,
32	    pub database: &'static str,
33	    #[serde(skip_serializing_if = "Option::is_none")]
34	    pub message: Option<String>,
35	}
36	
37	/// GET /health — liveness/readiness probe.
38	///
39	/// Attempts a lightweight `SELECT 1` against the pool to verify DB
40	/// reachability. Does **not** require authentication.
41	#[get("/health")]
42	pub async fn health_check(pool: &State<MySqlPool>) -> Json<Value> {
43	    let db_result = sqlx::query("SELECT 1")
44	        .execute(pool.inner())
45	        .await;
46	
47	    match db_result {
48	        Ok(_) => Json(serde_json::json!({
49	            "status": "ok",
50	            "database": "ok"
51	        })),
52	        Err(e) => Json(serde_json::json!({
53	            "status": "degraded",
54	            "database": "error",
55	            "message": e.to_string()
56	        })),
57	    }
58	}
59

1	//! Custom Rocket error catchers.
2	//!
3	//! These catchers intercept HTTP error responses that fall through the normal
4	//! handler chain (unmatched routes, guard failures that Rocket handles
5	//! directly, etc.) and format them in the same error envelope that every
6	//! `AppError` produces:
7	//!
8	//! ```json
9	//! { "error": { "code": "...", "message": "...", "request_id": "...", "fields": [] } }
10	//! ```
11	//!
12	//! Without custom catchers, Rocket emits its own JSON format for unmatched
13	//! routes (404) and body-deserialization failures (422), which breaks any
14	//! client that expects the documented envelope.
15	
16	use rocket::serde::json::Json;
17	use rocket::Request;
18	use serde_json::Value;
19	use uuid::Uuid;
20	
21	pub fn catchers() -> Vec<rocket::Catcher> {
22	    catchers![
23	        bad_request,
24	        unauthorized,
25	        forbidden,
26	        not_found,
27	        unprocessable_entity,
28	        internal_error
29	    ]
30	}
31	
32	/// Produce a standard error envelope with a fresh request-correlation ID.
33	fn envelope(code: &str, message: &str) -> Json<Value> {
34	    Json(serde_json::json!({
35	        "error": {
36	            "code": code,
37	            "message": message,
38	            "request_id": Uuid::new_v4().to_string(),
39	            "fields": []
40	        }
41	    }))
42	}
43	
44	#[catch(400)]
45	pub fn bad_request(_req: &Request) -> Json<Value> {
46	    envelope("bad_request", "The request could not be understood by the server.")
47	}
48	
49	#[catch(401)]
50	pub fn unauthorized(_req: &Request) -> Json<Value> {
51	    envelope("unauthorized", "Authentication is required to access this resource.")
52	}
53	
54	#[catch(403)]
55	pub fn forbidden(_req: &Request) -> Json<Value> {
56	    envelope("forbidden", "You do not have permission to perform this action.")
57	}
58	
59	#[catch(404)]
60	pub fn not_found(_req: &Request) -> Json<Value> {
61	    envelope("not_found", "The requested resource was not found.")
62	}
63	
64	#[catch(422)]
65	pub fn unprocessable_entity(_req: &Request) -> Json<Value> {
66	    envelope(
67	        "validation_error",
68	        "The request body could not be processed. Check the Content-Type and field formats.",
69	    )
70	}
71	
72	#[catch(500)]
73	pub fn internal_error(_req: &Request) -> Json<Value> {
74	    envelope("internal_error", "An unexpected server error occurred.")
75	}
76

