191	/// True if the principal holds *any* role that grants `cap`.
192	pub fn principal_can(principal: &Principal, cap: Capability) -> bool {
193	    principal.roles.iter().any(|r| role_allows(*r, cap))
194	}
195	
196	/// Return `Ok(())` if the principal has the capability, else `Forbidden`.
197	/// This is the one-line helper that service methods call as their first step.
198	pub fn require(principal: &Principal, cap: Capability) -> AppResult<()> {
199	    if principal_can(principal, cap) {
200	        Ok(())
201	    } else {
202	        Err(AppError::Forbidden)
203	    }
204	}
205	
206	/// Admin-only gate for admin config / user management / retention.
207	pub fn require_admin(principal: &Principal) -> AppResult<()> {
208	    if principal.is_admin() {
209	        Ok(())
210	    } else {
211	        Err(AppError::Forbidden)
212	    }
213	}
